#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=15;

int n,a[N],b[N];
ll M=1,ans;

long long exgcd(ll &x,ll &y,ll a,ll b){
    if(b==0){
        x=1,y=0;
        return a;
    }
    ll gcd=exgcd(x,y,b,a%b),t=x;
    x=y,y=t-a/b*y;
    return gcd;
}

ll solve(ll a,ll m){
    ll x,y;
    exgcd(x,y,a,m);
    return x;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        scanf("%d",&b[i]);
        a[i]=(a[i]%b[i]+b[i])%b[i];
        M*=b[i];
    }
    for(int i=1;i<=n;i++){
        ll t=solve(M/b[i],b[i]);
        ans=(ans+(__int128)a[i]*(M/b[i])%M*t%M)%M;
    }
    printf("%lld",(ans+M)%M);
    return 0;
}
